type Status = "pending" | "ack" | "error";
interface Row { id: string; body: string; status: Status; }

function send$(d: Draft): Observable<Row> {
  return of<Row>({ id: d.id, body: d.body, status: "ack" });
}

const outbox$ = new Subject<Draft>();
const rows$: Observable<Row> = outbox$.pipe(
  mergeMap((d: Draft) =>
    merge(
      of<Row>({ id: d.id, body: d.body, status: "pending" }),
      send$(d).pipe(
        map((r: Row) => r),
        catchError(() => of<Row>({ id: d.id, body: d.body, status: "error" }))
      )
    )
  )
);
rows$.subscribe((r: Row) => { void r; });
