Pull the optimistic-merge into an `OperatorFunction<Draft, Row>` so other pipelines (reactions, edits) can reuse it.

```typescript
import { OperatorFunction, Observable, Subject, of, merge, mergeMap, pipe } from "rxjs";

interface Draft { id: string; body: string; }
type Status = "pending" | "ack";
interface Row { id: string; body: string; status: Status; }

function withOptimistic(
  send$: (d: Draft) => Observable<Row>
): OperatorFunction<Draft, Row> {
  return pipe(
    mergeMap((d: Draft) =>
      merge(
        of<Row>({ id: d.id, body: d.body, status: "pending" }),
        send$(d)
      )
    )
  );
}

const outbox$ = new Subject<Draft>();
const rows$: Observable<Row> = outbox$.pipe(
  withOptimistic((d: Draft) => of<Row>({ id: d.id, body: d.body, status: "ack" }))
);
rows$.subscribe((r: Row) => { void r; });
```

