import { Subject, Observable, interval, takeUntil, map, scan, take } from "rxjs";

interface UploadEvent {
  uploaded: number;
  total: number;
  pct: number;
}

const cancel$ = new Subject<void>();

export function upload$(totalBytes: number, chunk: number): Observable<UploadEvent> {
  return interval(50).pipe(
    take(Math.ceil(totalBytes / chunk)),
    scan((acc: number) => acc + chunk, 0),
    map((uploaded: number): UploadEvent => {
      const capped = Math.min(uploaded, totalBytes);
      return { uploaded: capped, total: totalBytes, pct: capped / totalBytes };
    }),
    takeUntil(cancel$)
  );
}

upload$(1000, 100).subscribe((e: UploadEvent) => { void e; });
```

Model progress as an Observable that periodically emits bytes uploaded and stop it with `takeUntil(cancel$)` where `cancel$` is a Subject you `next()` when the user clicks Cancel. The upstream subscription tears down automatically on the first emission of the cancel Subject.

```typescript
import { Subject, Observable, interval, map, takeUntil, take } from "rxjs";

interface Progress { uploaded: number; total: number; }

export function upload$(total: number, cancel$: Subject<void>): Observable<Progress> {
  return interval(100).pipe(
    take(10),
    map((i: number): Progress => ({ uploaded: Math.min((i + 1) * (total / 10), total), total })),
    takeUntil(cancel$)
  );
}
```

The progress Observable emits raw chunk-bytes. `scan` folds those into a running total. `takeUntil(cancel$)` subscribes to a Subject you call next on from a cancel button; when it emits, the scan pipeline unsubscribes and cleans up. `scan` is like reduce but emits every intermediate value, which is what a progress bar wants.

```typescript
import { Subject, Observable, interval, take, scan, map, takeUntil } from "rxjs";

interface Progress { bytes: number; pct: number; }

const cancel$ = new Subject<void>();

export function run$(chunk: number, chunks: number): Observable<Progress> {
  const total = chunk * chunks;
  return interval(50).pipe(
    take(chunks),
    scan((acc: number) => acc + chunk, 0),
    map((bytes: number): Progress => ({ bytes, pct: bytes / total })),
    takeUntil(cancel$)
  );
}

run$(100, 5).subscribe((p: Progress) => { void p; });
```

