import { BehaviorSubject, Subject, Observable, interval, take, scan, map, switchMap, takeUntil, EMPTY } from "rxjs";

interface Progress { bytes: number; total: number; }

const cancel$ = new Subject<void>();
const paused$ = new BehaviorSubject<boolean>(false);

export function upload$(total: number, step: number): Observable<Progress> {
  const chunks = Math.ceil(total / step);
  const raw$ = interval(50).pipe(
    take(chunks),
    scan((acc: number) => acc + step, 0),
    map((bytes: number): Progress => ({ bytes: Math.min(bytes, total), total }))
  );
  return paused$.pipe(
    switchMap((p: boolean) => (p ? EMPTY : raw$)),
    takeUntil(cancel$)
  );
}

upload$(500, 100).subscribe((p: Progress) => { void p; });
