import { Subject, Observable, of, scan, switchMap, map, delay } from "rxjs";

interface Item { id: number; label: string; }
interface Page { items: readonly Item[]; pageIndex: number; }

function fetchPage$(page: number): Observable<Page> {
  const items: Item[] = [0, 1, 2].map((i) => ({
    id: page * 10 + i,
    label: `row-${page}-${i}`
  }));
  return of<Page>({ items, pageIndex: page }).pipe(delay(80));
}

const scroll$ = new Subject<void>();

export const items$: Observable<readonly Item[]> = scroll$.pipe(
  scan((page: number) => page + 1, -1),
  switchMap((page: number) => fetchPage$(page)),
  scan((acc: readonly Item[], p: Page) => [...acc, ...p.items], [] as readonly Item[]),
  map((xs: readonly Item[]) => xs)
);

items$.subscribe((xs: readonly Item[]) => { void xs; });
scroll$.next();
scroll$.next();
```

Use `switchMap` from the scroll trigger into `fetchPage$(page)`. `switchMap` unsubscribes from the prior inner observable when a new outer value arrives, so a rapid-fire scroll cancels any pending HTTP call and only the latest page wins.

```typescript
import { Subject, Observable, of, switchMap, scan, delay } from "rxjs";

interface Row { id: number; }

function page$(p: number): Observable<readonly Row[]> {
  return of<readonly Row[]>([{ id: p }]).pipe(delay(200));
}

const scroll$ = new Subject<void>();

export const rows$: Observable<readonly Row[]> = scroll$.pipe(
  scan((n: number) => n + 1, 0),
  switchMap((p: number) => page$(p))
);
```

`scan` turns an event stream (user hit the bottom) into a running page counter, which is stateful but declarative. `switchMap` then maps each page number into the fetch observable, cancelling the previous fetch if a new scroll arrives before the last page resolves. A second `scan` accumulates the fetched items into the visible list. Using `mergeMap` here would leak racing results onto the list.

```typescript
import { Subject, Observable, of, delay, scan, switchMap } from "rxjs";

interface Row { id: number; }

function fetch$(p: number): Observable<readonly Row[]> {
  return of<readonly Row[]>([{ id: p * 2 }, { id: p * 2 + 1 }]).pipe(delay(100));
}

const scroll$ = new Subject<void>();
export const list$: Observable<readonly Row[]> = scroll$.pipe(
  scan((p: number) => p + 1, -1),
  switchMap((p: number) => fetch$(p)),
  scan((acc: readonly Row[], batch: readonly Row[]) => [...acc, ...batch], [] as readonly Row[])
);
list$.subscribe((rs: readonly Row[]) => { void rs; });
```

