import { Observable, BehaviorSubject, combineLatest, of, delay, debounceTime, distinctUntilChanged, switchMap, map } from "rxjs";

interface Vm { username: string; email: string; usernameAvailable: boolean; formValid: boolean; }

const username$ = new BehaviorSubject<string>("");
const email$ = new BehaviorSubject<string>("");

function checkAvail$(u: string): Observable<boolean> {
  return of(u.length > 3 && u !== "taken").pipe(delay(60));
}

const avail$: Observable<boolean> = username$.pipe(
  debounceTime(300),
  distinctUntilChanged(),
  switchMap((u: string) => checkAvail$(u))
);

export const vm$: Observable<Vm> = combineLatest({
  username: username$,
  email: email$,
  usernameAvailable: avail$
}).pipe(
  map(({ username, email, usernameAvailable }): Vm => ({
    username, email, usernameAvailable,
    formValid: usernameAvailable && /@/.test(email)
  }))
);

vm$.subscribe((v: Vm) => { void v; });
```

