import { Observable, interval, of, delay, switchMap, takeWhile, map } from "rxjs";

type Phase = "queued" | "running" | "done" | "failed";
interface JobStatus { jobId: string; phase: Phase; progress: number; }

let tick = 0;
function fetchStatus$(jobId: string): Observable<JobStatus> {
  const phase: Phase =
    tick < 2 ? "queued" : tick < 5 ? "running" : "done";
  const progress = Math.min(tick * 0.2, 1);
  tick += 1;
  return of<JobStatus>({ jobId, phase, progress }).pipe(delay(20));
}

export function pollJob$(jobId: string): Observable<JobStatus> {
  return interval(500).pipe(
    switchMap(() => fetchStatus$(jobId)),
    takeWhile((s: JobStatus) => s.phase !== "done" && s.phase !== "failed", true),
    map((s: JobStatus) => s)
  );
}

pollJob$("job-1").subscribe((s: JobStatus) => { void s; });
```

Drive polling with `interval(ms)` and use `switchMap` into the status fetch. Because `switchMap` cancels any prior inner subscription when the outer emits, you never stack overlapping fetches; if the server is slow you simply drop the previous tick. Terminate with `takeWhile(s => s.phase !== 'done', true)` so the final emission is included.

```typescript
import { Observable, interval, of, switchMap, takeWhile, delay } from "rxjs";

type Phase = "running" | "done";
interface Status { phase: Phase; }

function check$(): Observable<Status> {
  return of<Status>({ phase: Math.random() > 0.7 ? "done" : "running" }).pipe(delay(30));
}

export const poll$: Observable<Status> = interval(500).pipe(
  switchMap(() => check$()),
  takeWhile((s: Status) => s.phase !== "done", true)
);
