import { Observable, interval, of, timer, throwError, switchMap, retry, takeWhile, map, delay } from "rxjs";

type Phase = "running" | "done";
interface Status { phase: Phase; }

let attempt = 0;
function unreliableCheck$(): Observable<Status> {
  attempt += 1;
  if (attempt === 2) return throwError(() => new Error("flaky"));
  return of<Status>({ phase: attempt > 4 ? "done" : "running" }).pipe(delay(10));
}

export const poll$: Observable<Status> = interval(200).pipe(
  switchMap(() =>
    unreliableCheck$().pipe(
      retry({ count: 3, delay: (_err: unknown, n: number) => timer(2 ** n * 50) })
    )
  ),
  takeWhile((s: Status) => s.phase !== "done", true),
  map((s: Status) => s)
);

poll$.subscribe((s: Status) => { void s; });
```

