import { Subject, Observable, of, delay, mergeMap } from "rxjs";

interface Conversation { id: string; }
interface Loaded { id: string; messages: number; }

function load$(c: Conversation): Observable<Loaded> {
  return of<Loaded>({ id: c.id, messages: 10 }).pipe(delay(40));
}

const open$ = new Subject<Conversation>();

// mergeMap with concurrency 3: up to 3 conversations load in parallel.
// switchMap would cancel prior loads; concatMap would serialize them.
export const loaded$: Observable<Loaded> = open$.pipe(
  mergeMap((c: Conversation) => load$(c), 3)
);

loaded$.subscribe((l: Loaded) => { void l; });
open$.next({ id: "c1" });
open$.next({ id: "c2" });
```

Use `forkJoin` with object form — it emits a single value once every inner observable has completed. Hot streams like `BehaviorSubject` don't complete, so feed it completing observables (e.g. `of`, HTTP).

```typescript
import { Observable, of, delay, forkJoin, map } from "rxjs";

interface Summary { users: number; revenue: number; }

const users$ = of(1234).pipe(delay(10));
const revenue$ = of(98765).pipe(delay(10));

export const summary$: Observable<Summary> = forkJoin({
  users: users$, revenue: revenue$
}).pipe(
  map(({ users, revenue }): Summary => ({ users, revenue }))
);
```

