import { Subject, Observable, interval, take, scan, map, takeUntil, shareReplay } from "rxjs";

interface Progress { bytes: number; total: number; pct: number; }

const cancel$ = new Subject<void>();

export function upload$(total: number, step: number): Observable<Progress> {
  const chunks = Math.ceil(total / step);
  return interval(50).pipe(
    take(chunks),
    scan((acc: number) => Math.min(acc + step, total), 0),
    map((bytes: number): Progress => ({ bytes, total, pct: bytes / total })),
    takeUntil(cancel$),
    shareReplay({ bufferSize: 1, refCount: true })
  );
}

const u$ = upload$(1000, 200);
u$.subscribe((p: Progress) => { void p; });
u$.subscribe((p: Progress) => { void p; });
```

