import { Subject, Observable, of, delay, merge, scan, switchMap } from "rxjs";

interface Row { id: number; }

function fetch$(p: number): Observable<readonly Row[]> {
  return of<readonly Row[]>([{ id: p * 2 }, { id: p * 2 + 1 }]).pipe(delay(60));
}

const scroll$ = new Subject<void>();
const initial$ = of<void>(undefined);

export const rows$: Observable<readonly Row[]> = merge(initial$, scroll$).pipe(
  scan((p: number) => p + 1, -1),
  switchMap((p: number) => fetch$(p)),
  scan((acc: readonly Row[], b: readonly Row[]) => [...acc, ...b], [] as readonly Row[])
);

rows$.subscribe((rs: readonly Row[]) => { void rs; });
scroll$.next();
